qry:select.qry:xquery:
		for $r in sql('			
	SELECT 
		PER02_PERSONAL_EMP.oi_personal_emp
	FROM 
		PER02_PERSONAL_EMP
		{%?('##oi_liquidacion##'!='') 
			{% , TTA10_LIQUIDACPERS
			JOIN
				PER02_PERSONAL_EMP.oi_personal_emp INNER TTA10_LIQUIDACPERS.oi_personal_emp %} 
			{% %} 
		%}
	WHERE 
		1 = 1
		{%?('##oi_liquidacion##'!='') 
			{% AND TTA10_LIQUIDACPERS.oi_liquidacion = ##oi_liquidacion## %} 
			{% %} 
		%}
')/ROWS/ROW

form:Form.form:Scripts:
		function Find()
{
	Ctrl("Conceptos").filter("",Ctrl("iter_search").GetCValue());
}

function ClearCONC()
{
	Ctrl("CONC").DelAllRow();
	Ctrl("Conceptos").Refresh();
}

function FullCONC()
{
	Ctrl("CONC").DelAllRow();     
	for (var t=0; t<Ctrl("Conceptos").TotalRowsCount(); t++)
		Ctrl("CONC").AddRow().SetAttr("id", Ctrl("Conceptos").GetAttrValue(t, "id"));

	Ctrl("Conceptos").Refresh();
}

function SetDates()
{
	var fechas;				
	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();

	if(Ctrl("oi_liquidacion").GetXValue() != "")
	{	
		fechas = nSQL.GetOBJ(Ctrl("main").getResource("QRY_FECHAS"), "<PARAM oi_liquidacion=\""+Ctrl("oi_liquidacion").GetXValue()+"\" />"); 				
		Ctrl("f_desde").SetXValue(fechas.f_fechainicio);				
		Ctrl("f_hasta").SetXValue(fechas.f_fechafin);
		Ctrl("f_ini").SetXValue(fechas.f_fechainicio);				
		Ctrl("f_fin").SetXValue(fechas.f_fechafin);
	}
}

function ONLOAD_custom()
{
	SetDates();
} 

function Ejecutar()
{
 if(Ctrl("oi_liquidacion").GetXValue() != "")
 {
	 if((Ctrl("f_desde").GetXValue() < Ctrl("f_ini").GetXValue() || Ctrl("f_desde").GetXValue() > Ctrl("f_fin").GetXValue()) || (Ctrl("f_hasta").GetXValue() < Ctrl("f_ini").GetXValue() || Ctrl("f_hasta").GetXValue() > Ctrl("f_fin").GetXValue()))
	 {
		alert("El rango de fechas se encuentra fuera del procesamiento");
		return false; 	
	 }  
 }
 if (Ctrl("list2").TotalRowsCount()==0)
 {             
	alert("No hay legajos filtrados.");
 	return false;
 }

 if (Ctrl("CONC").CountRow()==0)
 {		
 	alert("Debe seleccionar al menos un Concepto");
    return false; 
 }


 Ctrl('legajos').DelAllRow();
 for (key in arrB) Ctrl('legajos').AddRow().SetAttr('id', key.substr(1));

 Ctrl("main").DoEvent("FILTER");	
}
